create table "_RebateBaseSchema"
(
    "Id"          bigint generated by default as identity
        constraint "_RebateBaseSchema_Id_uindex"
            primary key,
    "CreatedBy"   bigint                                                 not null
        constraint "_RebateBaseSchema__Party_Id_fk"
            references core."_Party",
    "CreatedOn"   timestamp with time zone default now()                 not null,
    "UpdatedOn"   timestamp with time zone default now()                 not null,
    "Name"        varchar(64)              default ''::character varying not null,
    "Note"        varchar(256)             default ''::character varying not null,
    "LevelSchema" json                     default '{}'::json            not null,
    "Pips"        json                     default '{}'::json            not null,
    "Commission"  json                     default '{}'::json            not null,
    "Schema"      json                     default '{}'::json            not null
);

alter table "_RebateBaseSchema"
    owner to bcrpro;

create index "_RebateBaseSchema_CreatedBy_index"
    on "_RebateBaseSchema" ("CreatedBy");

grant select on "_RebateBaseSchema" to dev_read;

create table "_RebateBaseSchemaItem"
(
    "Id"                 bigint generated by default as identity
        constraint "_RebateBaseSchemaItem_pk"
            primary key,
    "RebateBaseSchemaId" bigint                                 not null
        constraint "_RebateBaseSchemaItem__RebateBaseSchema_Id_fk"
            references "_RebateBaseSchema"
            on delete cascade,
    "Rate"               numeric(16, 2)                         not null,
    "Pips"               numeric(16, 2)                         not null,
    "Commission"         numeric(16, 2)                         not null,
    "CreatedOn"          timestamp with time zone default now() not null,
    "UpdatedOn"          timestamp with time zone default now() not null,
    "SymbolCode"         varchar(64)                            not null
);

alter table "_RebateBaseSchemaItem"
    owner to bcrpro;

create index "_RebateBaseSchemaItem_RebateRuleId_index"
    on "_RebateBaseSchemaItem" ("RebateBaseSchemaId");

create index "_RebateBaseSchemaItem_SymbolCode_index"
    on "_RebateBaseSchemaItem" ("SymbolCode");

grant select on "_RebateBaseSchemaItem" to dev_read;

